pair A,C,P,O,D;

draw((0,-1.2)--(0,1.2),p=black+1.2bp,Arrows(0.15cm));

draw((-1.2,0)--(1.2,0),p=black+1.2bp,Arrows(0.15cm));

A = (1,0);

O= (0,0);

label("$x$",(1.2,0),SE);

label("$y$",(0,1.2),NE);

P = rotate(315)*A;

D = foot(P,A,-A);

draw(O--P--D);

draw(rightanglemark(O,D,P,2));

draw(Circle(O,1));

label("$O$",O,NW);

label("$P$",P,SE);

//label("$A$",A,SE);

label("$D$",D,N);

[/asy]

Triangle $POD$ is a 45-45-90 triangle, so $DO = DP = \frac{\sqrt{2}}{2}$.  Therefore, the coordinates of $P$ are $\left(\frac{\sqrt{2}}{2}, -\frac{\sqrt{2}}{2}\right)$, so $\tan 315^\circ = \frac{\sin 315^\circ}{\cos 315^\circ} = \frac{-\sqrt{2}/2}{\sqrt{2}/2} = \boxed{-1}$.

The curve describes a semicircle with radius 2.  Therefore, the length of the curve is
\[\frac{1}{2} \cdot 2 \pi \cdot 2 = \boxed{2 \pi}.\][asy]
unitsize(1 cm);

pair moo (real t) {
  return (2*sin(t),2*cos(t));
}

real t;
path foo = moo(0);

for (t = 0; t <= pi; t = t + 0.01) {
  foo = foo--moo(t);
}

draw((-2.5,0)--(2.5,0));
draw((0,-2.5)--(0,2.5));
draw(foo,red);

label("$2$", (1,0), S);

dot("$t = 0$", moo(0), W);
dot("$t = \pi$", moo(pi), W);
[/asy]

